// Enhanced NIFTY Exit Order Monitor for Dhan API
const orderBook = $node['Get Dhan Order Book'].json.data || [];
const activeTrades = $node['Get Active NIFTY Trades'].json || [];
const accessToken = $node['Dhan Authentication'].json.data.access_token;

const results = [];
const ordersToCancel = [];
const tradesToUpdate = [];
const notifications = [];

// Process each active NIFTY trade
activeTrades.forEach(tradeRow => {
  if (tradeRow.Status !== 'ACTIVE' || tradeRow.Underlying !== 'NIFTY') return;

  const entryOrderId = tradeRow['Entry Order ID'];
  const slOrderId = tradeRow['SL Order ID'];
  const targetOrderId = tradeRow['Target Order ID'];
  const tradingSymbol = tradeRow['Trading Symbol'];
  const entryPrice = parseFloat(tradeRow['Entry Price']);
  const quantity = parseInt(tradeRow['Quantity']);

  // Find these orders in the current order book
  const slOrder = orderBook.find(order => order.orderId === slOrderId);
  const targetOrder = orderBook.find(order => order.orderId === targetOrderId);

  let executedOrder = null;
  let orderToCancel = null;
  let exitType = null;
  let exitPrice = null;
  let pnl = 0;

  // Check if SL order is executed
  if (slOrder && slOrder.orderStatus === 'TRADED') {
    executedOrder = slOrder;
    orderToCancel = targetOrderId;
    exitType = 'STOP_LOSS';
    exitPrice = parseFloat(slOrder.price);
    pnl = (exitPrice - entryPrice) * quantity;

    notifications.push({
      type: 'NIFTY_STOP_LOSS_HIT',
      message: `NIFTY Stop Loss executed for ${tradingSymbol} at ₹${exitPrice}`,
      pnl: pnl,
      severity: pnl < 0 ? 'HIGH' : 'MEDIUM',
      underlying: 'NIFTY'
    });
  }
  // Check if Target order is executed
  else if (targetOrder && targetOrder.orderStatus === 'TRADED') {
    executedOrder = targetOrder;
    orderToCancel = slOrderId;
    exitType = 'TARGET';
    exitPrice = parseFloat(targetOrder.price);
    pnl = (exitPrice - entryPrice) * quantity;

    notifications.push({
      type: 'NIFTY_TARGET_ACHIEVED',
      message: `NIFTY Target achieved for ${tradingSymbol} at ₹${exitPrice}`,
      pnl: pnl,
      severity: 'LOW',
      underlying: 'NIFTY'
    });
  }
  // Check for partial executions or pending status changes
  else {
    // Monitor for any status changes that might need attention
    if (slOrder && slOrder.orderStatus === 'REJECTED') {
      notifications.push({
        type: 'NIFTY_SL_ORDER_REJECTED',
        message: `NIFTY SL order rejected for ${tradingSymbol}`,
        severity: 'HIGH',
        underlying: 'NIFTY'
      });
    }

    if (targetOrder && targetOrder.orderStatus === 'REJECTED') {
      notifications.push({
        type: 'NIFTY_TARGET_ORDER_REJECTED',
        message: `NIFTY Target order rejected for ${tradingSymbol}`,
        severity: 'HIGH',
        underlying: 'NIFTY'
      });
    }
  }

  if (executedOrder && orderToCancel) {
    // Add order to cancel list
    ordersToCancel.push({
      orderId: orderToCancel,
      tradingSymbol: tradingSymbol,
      underlying: 'NIFTY'
    });

    // Calculate additional NIFTY-specific metrics
    const riskAmount = Math.abs(entryPrice - parseFloat(tradeRow['Stop Loss']));
    const rewardAmount = Math.abs(parseFloat(tradeRow['Target']) - entryPrice);
    const actualRR = exitType === 'TARGET' ? 
      Math.abs(pnl) / (riskAmount * quantity) : 
      -Math.abs(pnl) / (riskAmount * quantity);

    // Update trade information
    tradesToUpdate.push({
      entryOrderId: entryOrderId,
      exitType: exitType,
      exitPrice: exitPrice,
      pnl: Math.round(pnl * 100) / 100,
      executedOrderId: executedOrder.orderId,
      actualRiskReward: Math.round(actualRR * 100) / 100,
      executionTime: executedOrder.updateTime || new Date().toISOString(),
      timestamp: new Date().toISOString(),
      underlying: 'NIFTY'
    });

    results.push({
      message: `NIFTY ${exitType} executed for ${tradingSymbol}`,
      entryOrderId: entryOrderId,
      tradingSymbol: tradingSymbol,
      exitPrice: exitPrice,
      pnl: pnl,
      cancelOrderId: orderToCancel,
      exitType: exitType,
      underlying: 'NIFTY'
    });
  }
});

// Calculate NIFTY session statistics
const sessionStats = {
  totalExecutions: results.length,
  totalPnL: tradesToUpdate.reduce((sum, trade) => sum + trade.pnl, 0),
  targetHits: tradesToUpdate.filter(t => t.exitType === 'TARGET').length,
  stopLossHits: tradesToUpdate.filter(t => t.exitType === 'STOP_LOSS').length,
  avgPnL: tradesToUpdate.length > 0 ? 
    tradesToUpdate.reduce((sum, trade) => sum + trade.pnl, 0) / tradesToUpdate.length : 0,
  underlying: 'NIFTY'
};

return {
  results,
  ordersToCancel,
  tradesToUpdate,
  notifications,
  sessionStats,
  totalExecutions: results.length,
  timestamp: new Date().toISOString()
};

// Prepare NIFTY order cancellations with enhanced error handling
const ordersToCancel = $node['Analyze NIFTY Exit Executions'].json.ordersToCancel;
const cancelResults = [];

for (const order of ordersToCancel) {
  cancelResults.push({
    orderId: order.orderId,
    tradingSymbol: order.tradingSymbol,
    underlying: order.underlying,
    timestamp: new Date().toISOString()
  });
}

return cancelResults;

// Process NIFTY notifications and alerts
const notifications = $node['Analyze NIFTY Exit Executions'].json.notifications;
const sessionStats = $node['Analyze NIFTY Exit Executions'].json.sessionStats;

const alerts = [];
const highPriorityAlerts = [];

notifications.forEach(notification => {
  const alert = {
    timestamp: new Date().toISOString(),
    type: notification.type,
    message: notification.message,
    severity: notification.severity,
    pnl: notification.pnl || 0,
    underlying: 'NIFTY'
  };

  alerts.push(alert);

  // High priority alerts for NIFTY
  if (notification.severity === 'HIGH') {
    highPriorityAlerts.push(alert);
  }
});

// Add NIFTY session summary if significant activity
if (sessionStats.totalExecutions > 0) {
  const summaryAlert = {
    timestamp: new Date().toISOString(),
    type: 'NIFTY_SESSION_SUMMARY',
    message: `NIFTY Session Update: ${sessionStats.totalExecutions} executions, Total PnL: ₹${sessionStats.totalPnL.toFixed(2)}`,
    severity: sessionStats.totalPnL >= 0 ? 'LOW' : 'MEDIUM',
    sessionStats: sessionStats,
    underlying: 'NIFTY'
  };

  alerts.push(summaryAlert);
}

return {
  alerts,
  highPriorityAlerts,
  totalAlerts: alerts.length,
  highPriorityCount: highPriorityAlerts.length
};
